// Try to find and click the destination input field
const destField = document.querySelector('input[placeholder="Where to?"], input[aria-label*="destination"], input[aria-label*="Destination"]');
if (destField) {
    destField.click();
    destField.value = 'Chicago';
    destField.dispatchEvent(new Event('input', { bubbles: true }));
    console.log('Destination field found and clicked');
} else {
    console.log('Destination field not found');
}

// List all input fields
const inputs = document.querySelectorAll('input');
inputs.forEach((input, i) => {
    console.log(i, input.placeholder, input.ariaLabel, input.value);
});

